// AuthInterceptor.kt
class AuthInterceptor : Interceptor {
    var authToken: String? = null
    
    override fun intercept(chain: Interceptor.Chain): Response {
        val originalRequest = chain.request()
        val requestBuilder = originalRequest.newBuilder()
        
        authToken?.let {
            requestBuilder.addHeader("Authorization", "Bearer $it")
        }
        
        return chain.proceed(requestBuilder.build())
    }
}

// NetworkModule.kt
object NetworkModule {
    private val authInterceptor = AuthInterceptor()
    
    private val loggingInterceptor = HttpLoggingInterceptor().apply {
        level = if (BuildConfig.DEBUG) {
            HttpLoggingInterceptor.Level.BODY
        } else {
            HttpLoggingInterceptor.Level.NONE
        }
    }
    
    private val okHttpClient = OkHttpClient.Builder()
        .addInterceptor(authInterceptor)
        .addInterceptor(loggingInterceptor)
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .writeTimeout(30, TimeUnit.SECONDS)
        .build()
    
    private val retrofit: Retrofit by lazy {
        Retrofit.Builder()
            .baseUrl(NetworkConfig.currentEnvironment.baseUrl)
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
    }
    
    val apiService: ApiService by lazy {
        retrofit.create(ApiService::class.java)
    }
    
    fun setAuthToken(token: String?) {
        authInterceptor.authToken = token
    }
    
    fun setEnvironment(environment: Environment) {
        NetworkConfig.currentEnvironment = environment
    }
}

// ApiResult.kt
sealed class ApiResult<out T> {
    data class Success<T>(val data: T) : ApiResult<T>()
    data class Error(val message: String, val code: Int? = null) : ApiResult<Nothing>()
    object Loading : ApiResult<Nothing>()
}

// UserRepository.kt
class UserRepository {
    private val apiService = NetworkModule.apiService
    
    suspend fun getUserProfile(userId: Int): ApiResult<User> {
        return try {
            val response = apiService.getUserProfile(userId)
            ApiResult.Success(response.data)
        } catch (e: HttpException) {
            ApiResult.Error(
                message = e.message() ?: "HTTP error occurred",
                code = e.code()
            )
        } catch (e: IOException) {
            ApiResult.Error(message = "Network error: ${e.message}")
        } catch (e: Exception) {
            ApiResult.Error(message = "Unknown error: ${e.message}")
        }
    }
    
    suspend fun getAllUsers(): ApiResult<List<User>> {
        return try {
            val response = apiService.getAllUsers()
            ApiResult.Success(response.data)
        } catch (e: HttpException) {
            ApiResult.Error(
                message = e.message() ?: "HTTP error occurred",
                code = e.code()
            )
        } catch (e: IOException) {
            ApiResult.Error(message = "Network error: ${e.message}")
        } catch (e: Exception) {
            ApiResult.Error(message = "Unknown error: ${e.message}")
        }
    }
}

